      ctx.textAlign = 'center';
      ctx.fillStyle = '#e8dcb8';
      ctx.strokeStyle = '#8b6914';
      ctx.lineWidth = 0.5;

      // Draw text with stroke for embossed effect
      const textTop = "WASTEDTOKEN";
      const metrics = ctx.measureText(textTop);
      const tx = w/2 - metrics.width/2;
      const ty = h*0.18;
      ctx.strokeText(textTop, tx, ty);
