      bgGrad.addColorStop(0, '#2a2835');
      bgGrad.addColorStop(1, '#1a1620');
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, w, h);

      // Outer ring (border) - slightly different color for back
      const ringGrad = ctx.createLinearGradient(0, 0, w, h);
      ringGrad.addColorStop(0, '#8b7355');
      ringGrad.addColorStop(1, '#4a3a2a');
      ctx.strokeStyle = ringGrad;
      ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.arc(w/2, h/2, w*0.38, 0, Math.PI * 2);
      ctx.stroke();

      // Inner circle - denomination area
      const innerGrad = ctx.createRadialGradient(w/2, h/2, w*0.15, w/2, h/2, w*0.45);
      innerGrad.addColorStop(0, '#d4c8a8');
      innerGrad.addColorStop(1, '#b8a878');
      ctx.fillStyle = innerGrad;
      ctx.beginPath();
      ctx.arc(w/2, h/2, w*0.35, 0, Math.PI * 2);
      ctx.fill();

      // "TOKENS" text - large, bold
      ctx.save();
      ctx.font = 'bold 48px "Segoe UI", sans-serif';
      ctx.textAlign = 'center';
      ctx.fillStyle = '#1a1610';
      ctx.strokeStyle = '#2a2835';
      ctx.lineWidth = 1.5;

      const tokensText = "TOKENS";
      const tMetrics = ctx.measureText(tokensText);
      const tx = w/2 - tMetrics.width/2;
      const ty = h*0.42;
      ctx.strokeText(tokensText, tx, ty);
      ctx.fillText(tokensText, tx, ty);

      // "10,000" above TOKENS
      ctx.font = 'bold 36px "Segoe UI", sans-serif';
      const numMetrics = ctx.measureText("10,000");
      const ntx = w/2 - numMetrics.width/2;
      const nty = h*0.35;
      ctx.strokeText("10,000", ntx, nty);
      ctx.fillText("10,000", ntx, nty);

      // Divider line
      ctx.strokeStyle = '#8b7355';
      ctx.lineWidth = 0.5;
      ctx.beginPath();
      ctx.moveTo(w*0.25, h*0.46);
      ctx.lineTo(w*0.75, h*0.46);
      ctx.stroke();

      // "DENOMINATION" label below
      ctx.font = '12px "Segoe UI", sans-serif';
      ctx.fillStyle = '#8b7355';
      const denomMetrics = ctx.measureText("DENOMINATION");
      ctx.fillText(denomMetrics, w/2 - denomMetrics.width/2, h*0.6);

      // Small decorative elements (dots)
      ctx.fillStyle = '#8b7355';
      for (let i = 0; i < 4; i++) {
        const angle = (i * Math.PI) / 2 - Math.PI/2 + 0.1;
        const dx = w*0.3 + Math.cos(angle) * w*0.15;
        const dy = h*0.7 + Math.sin(angle) * w*0.15;
        ctx.beginPath();
        ctx.arc(dx, dy, w*0.02, 0, Math.PI * 2);
        ctx.fill();
      }

      // Subtle radial highlight
      const hlGrad = ctx.createRadialGradient(w/2, h/2, 0, w/2, h/2, w*0.3);
      hlGrad.addColorStop(0, 'rgba(255,255,255,0.08)');
      hlGrad.addColorStop(1, 'transparent');
      ctx.fillStyle = hlGrad;
      ctx.fillRect(0, 0, w, h);

      ctx.restore();
