    return c;
  }

  // ---- WEBGL SETUP ----
  const canvas = document.getElementById('coin-hero');
  const gl = canvas.getContext('webgl', { antialias: true, alpha: false });

  if (!gl) { alert('WebGL not supported'); return; }

  function compileShader(type, source) {
    const s = gl.createShader(type);
    gl.shaderSource(s, source);
    gl.compileShader(s);
    if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
      console.error('Shader error:', gl.getShaderInfoLog(s));
      return null;
    }
    return s;
  }

  const vsSource = `
    attribute vec3 aPosition;
    attribute vec2 aTexCoord;
    attribute vec3 aNormal;

    uniform mat4 uModelMatrix;
    uniform mat4 uViewMatrix;
    uniform mat4 uProjMatrix;

    varying vec2 vTexCoord;
    varying vec3 vNormal;
    varying vec3 vWorldPos;

    void main() {
      vTexCoord = aTexCoord;
      vNormal = normalize(mat3(uModelMatrix) * aNormal);
      vec4 worldPos = uModelMatrix * vec4(aPosition, 1.0);
      vWorldPos = worldPos.xyz;
      gl_Position = uProjMatrix * uViewMatrix * worldPos;
    }
  `;

  const fsSource = `
    precision mediump float;

    varying vec2 vTexCoord;
    varying vec3 vNormal;
    varying vec3 vWorldPos;

    uniform sampler2D uFrontTexture;
    uniform sampler2D uBackTexture;
    uniform float uIsBackFace; // 0.0 = front, 1.0 = back
    uniform vec3 uBaseColor;
    uniform vec3 uLightDir;
    uniform vec3 uViewDir;

    void main() {
      // Select texture based on face
      vec4 texColor;
      if (uIsBackFace > 0.5) {
        texColor = texture2D(uBackTexture, vTexCoord);
      } else {
        texColor = texture2D(uFrontTexture, vTexCoord);
      }

      // Normal-based lighting
      vec3 N = normalize(vNormal);
      vec3 L = normalize(uLightDir);
      vec3 V = normalize(uViewDir);

      float ndotl = max(dot(N, L), 0.0);

      // Half vector for specular
      vec3 H = normalize(L + V);
      float ndoth = max(dot(N, H), 0.0);

      // Metallic PBR-like model
      float metallicFactor = 0.95;

      // Specular highlight - strong and concentrated for metallic look
      float specular = pow(ndoth, 128.0) * metallicFactor;

      // Ambient + diffuse
      float diff = ndotl * (1.0 - metallicFactor);

      // Rim lighting for edge definition
      float rim = pow(1.0 - ndotl, 4.0) * 0.3;

      // Base color from texture with metallic tint
      vec3 baseColor = texColor.rgb * uBaseColor + vec3(metallicFactor);

      // Combine lighting
      vec3 litColor = baseColor * (diff + specular * 2.0) + rim * vec3(0.5, 0.4, 0.6);

      // Add subtle edge highlight for reeded effect
      float edgeStrength = pow(length(N.z), 8.0) * 0.1;
      litColor += edgeStrength * vec3(0.8, 0.7, 0.5);

      gl_FragColor = vec4(litColor, texColor.a);
    }
  `;

  const vs = compileShader(gl.VERTEX_SHADER, vsSource);
  const fs = compileShader(gl.FRAGMENT_SHADER, fsSource);
  const program = gl.createProgram();
  gl.attachShader(program, vs);
  gl.attachShader(program, fs);
  gl.linkProgram(program);
  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
    console.error('Program error:', gl.getProgramInfoLog(program));
    return;
  }
  gl.useProgram(program);

  // ---- UNIFORM LOCATIONS ----
  const uModel = gl.getUniformLocation(program, 'uModelMatrix');
  const uView = gl.getUniformLocation(program, 'uViewMatrix');
  const uProj = gl.getUniformLocation(program, 'uProjMatrix');
  const uFrontTex = gl.getUniformLocation(program, 'uFrontTexture');
  const uBackTex = gl.getUniformLocation(program, 'uBackTexture');
  const uIsBackFace = gl.getUniformLocation(program, 'uIsBackFace');
  const uBaseColor = gl.getUniformLocation(program, 'uBaseColor');
  const uLightDir = gl.getUniformLocation(program, 'uLightDir');
  const uViewDir = gl.getUniformLocation(program, 'uViewDir');

  // ---- GEOMETRY GENERATION ----
  function createCoinGeometry(radius, thickness) {
    const segments = 64;
    const vertices = [];
    const texCoords = [];
    const normals = [];

    // Helper to add a vertex ring (front or back face)
    function addRing(faceDir, isBack) {
      for (let i = 0; i <= segments; i++) {
        const angle = (i / segments) * Math.PI * 2;
        const x = Math.cos(angle) * radius;
        const z = Math.sin(angle) * radius;

        // Front face normal points +Z, back face -Z
        const nx = isBack ? -x : x;
        const nz = isBack ? -z : z;
        const nlen = Math.sqrt(nx*nx + nz*nz);
        const normX = nx / (nlen || 1);
        const normZ = nz / (nlen || 1);

        vertices.push(x, thickness/2, z); // position front
        texCoords.push(0.5 + Math.cos(angle) * 0.3, 0.5 + Math.sin(angle) * 0.3);
        normals.push(normX, 0.0, normZ);

        vertices.push(x, -thickness/2, z); // position back
        texCoords.push(0.5 + Math.cos(angle) * 0.3, 0.5 + Math.sin(angle) * 0.3);
        normals.push(-normX, 0.0, -normZ);
      }
    }

    addRing(radius, false); // front face ring
    addRing(radius, true);  // back face ring

    // Side faces (connecting front to back)
    for (let i = 0; i < segments; i++) {
      const angle1 = (i / segments) * Math.PI * 2;
      const angle2 = ((i + 1) / segments) * Math.PI * 2;

      const x1 = Math.cos(angle1) * radius, z1 = Math.sin(angle1) * radius;
      const x2 = Math.cos(angle2) * radius, z2 = Math.sin(angle2) * radius;

      // Side quad: front-top -> back-top -> back-bottom -> front-bottom
      vertices.push(x1, thickness/2, z1);
      texCoords.push(0.5 + Math.cos(angle1)*0.3, 0.5 + Math.sin(angle1)*0.3);
      normals.push(0, 0, 1);

      vertices.push(x2, thickness/2, z2);
      texCoords.push(0.5 + Math.cos(angle2)*0.3, 0.5 + Math.sin(angle2)*0.3);
      normals.push(0, 0, 1);

      vertices.push(x2, -thickness/2, z2);
      texCoords.push(0.5 + Math.cos(angle2)*0.3, 0.5 + Math.sin(angle2)*0.3);
      normals.push(0, 0, -1);

      vertices.push(x1, -thickness/2, z1);
      texCoords.push(0.5 + Math.cos(angle1)*0.3, 0.5 + Math.sin(angle1)*0.3);
      normals.push(0, 0, -1);
    }

    // REEDED EDGE: Create ridges around the rim
    const ridgeCount = 8;
    for (let r = 0; r < ridgeCount; r++) {
      const offset = (r % 2 === 0) ? radius + thickness*0.3 : radius - thickness*0.15;
      addRing(offset, false); // front face of ridge
      addRing(offset, true);  // back face of ridge

      // Side faces for ridges
      for (let i = 0; i < segments; i++) {
        const angle1 = (i / segments) * Math.PI * 2;
        const angle2 = ((i + 1) / segments) * Math.PI * 2;

        const x1 = Math.cos(angle1) * offset, z1 = Math.sin(angle1) * offset;
        const x2 = Math.cos(angle2) * offset, z2 = Math.sin(angle2) * offset;

        vertices.push(x1, thickness/2, z1);
        texCoords.push(0.5 + Math.cos(angle1)*0.3, 0.5 + Math.sin(angle1)*0.3);
        normals.push(0, 0, 1);

        vertices.push(x2, thickness/2, z2);
        texCoords.push(0.5 + Math.cos(angle2)*0.3, 0.5 + Math.sin(angle2)*0.3);
        normals.push(0, 0, 1);

        vertices.push(x2, -thickness/2, z2);
        texCoords.push(0.5 + Math.cos(angle2)*0.3, 0.5 + Math.sin(angle2)*0.3);
        normals.push(0, 0, -1);

        vertices.push(x1, -thickness/2, z1);
        texCoords.push(0.5 + Math.cos(angle1)*0.3, 0.5 + Math.sin(angle1)*0.3);
        normals.push(0, 0, -1);
      }
    }

    // Index buffer: pairs of (front vertex index, back vertex index) for each ring segment
    const indices = [];

    // Front face triangles
    for (let i = 0; i < segments; i++) {
      const fi = i * 2;
      const ni = (i + 1) * 2;
      indices.push(fi, ni, fi+1);
      indices.push(ni, ni+1, fi+1);
    }

    // Back face triangles (reversed winding for back-face culling)
    for (let i = 0; i < segments; i++) {
      const fi = i * 2;
      const ni = (i + 1) * 2;
      indices.push(ni, fi+1, fi);
      indices.push(fi+1, ni+1, fi);
    }

    // Side face quads as two triangles each
    for (let i = 0; i < segments; i++) {
      const base = i * 4;
      indices.push(base, base+2, base+1);
      indices.push(base, base+1, base+3);
    }

    // Ridge side faces
    for (let r = 0; r < ridgeCount; r++) {
      const offsetBase = segments * 4 + r * segments * 4;
      for (let i = 0; i < segments; i++) {
        const base = offsetBase + i * 4;
        indices.push(base, base+2, base+1);
        indices.push(base, base+1, base+3);
      }
    }

    return { vertices: new Float32Array(vertices), texCoords: new Float32Array(texCoords), normals: new Float32Array(normals), indices: new Uint16Array(indices) };
  }

