    // The isBackFace uniform tells the shader which texture to use
    gl.drawElements(gl.TRIANGLES, coinGeo.indices.length, gl.UNSIGNED_SHORT, 0);

    lastTime = performance.now();
    requestAnimationFrame(render);
  }

  const projectionMatrix = getViewMatrix(); // Use same as view for simplicity (orthographic-like)

  // ---- PUBLIC API ----
  window.demo = {
