    },

    pause() {
      isPaused = true;
      cancelAnimationFrame(lastTime);
    }
  };

  // ---- ANIMATION LOOP ----
  function animate() {
    const now = performance.now();
    if (lastTime === null) lastTime = now;
    let elapsed = (now - lastTime) / 1000;

    // Loop period: ~3 seconds for one full rotation
    elapsed = Math.floor(elapsed / 3.0) % 1.0;

    render(elapsed);
    lastTime = now;
    requestAnimationFrame(animate);
